// Grid configuration
export const GRID_COLS = 29;
export const GRID_ROWS = 16;
export const TOTAL_CELLS = GRID_COLS * GRID_ROWS;
export const MAX_STUDENTS = 30;
export const MAX_NAME_LENGTH = 20;
export const DEFAULT_PIN = "0000";
export const PIN_MAX_ATTEMPTS = 5;
export const PIN_LOCKOUT_SECONDS = 30;
export const AUTO_LOCK_SECONDS = 120;
export const LONG_PRESS_MS = 2000;

// Default student data structure
export interface StudentData {
  id: string;
  name: string;
  eggs: boolean[][]; // [col][row] - 29 cols x 16 rows
  dates: string[]; // 29 dates in M/D format
  goals: number[]; // 29 goals (0-16)
  soundEnabled: boolean;
}

export interface AppState {
  students: StudentData[];
  currentStudentId: string | null;
  selectedCol: number | null;
  pin: string;
}

export function createEmptyEggs(): boolean[][] {
  return Array.from({ length: GRID_COLS }, () =>
    Array.from({ length: GRID_ROWS }, () => false)
  );
}

export function createEmptyDates(): string[] {
  return Array.from({ length: GRID_COLS }, () => "");
}

export function createEmptyGoals(): number[] {
  return Array.from({ length: GRID_COLS }, () => 0);
}

export function createNewStudent(name: string): StudentData {
  return {
    id: crypto.randomUUID ? crypto.randomUUID() : Date.now().toString(),
    name,
    eggs: createEmptyEggs(),
    dates: createEmptyDates(),
    goals: createEmptyGoals(),
    soundEnabled: false,
  };
}
